namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 uppercase alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and fundamental forces." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", Code = "CS 101", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures & Algorithms", Code = "CS 201", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithmic complexity and has published over 40 papers in top-tier conferences.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Database Systems", Code = "CS 305", Description = "Design and implementation of relational databases, SQL, normalization, indexing, and transaction management.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Rodriguez", InstructorBio = "Dr. Rodriguez worked at Oracle for 10 years before joining academia. Her research focuses on distributed database systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", Code = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Alan Whitfield", InstructorBio = "Dr. Whitfield is an award-winning educator with a passion for making calculus accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", Code = "MATH 220", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma's research interests include numerical linear algebra and scientific computing.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "Statistics & Probability", Code = "MATH 310", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", InstructorName = "Dr. Alan Whitfield", InstructorBio = "Dr. Whitfield is an award-winning educator with a passion for making calculus accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 7, Title = "General Physics I", Code = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM + Fri Lab", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an experimental physicist whose work on quantum optics has been featured in Nature.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 8, Title = "Electromagnetism", Code = "PHYS 202", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Lisa Fernandez", InstructorBio = "Dr. Fernandez brings 20 years of research experience in condensed matter physics to the classroom.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Title = "English Composition", Code = "ENG 101", Description = "Develop critical reading and writing skills. Focus on argumentative essays and research papers.", Credits = 3, Schedule = "Mon/Wed 9:00–10:20 AM", InstructorName = "Prof. David Okafor", InstructorBio = "Prof. Okafor is a published author and writing coach who has helped thousands of students improve their prose.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "American Literature", Code = "ENG 250", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson specializes in 20th-century American fiction and has authored two books on the Harlem Renaissance.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 11, Title = "World History to 1500", Code = "HIST 101", Description = "Survey of world civilizations from prehistory to 1500 CE, covering political, social, and cultural developments.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is an archaeologist-turned-historian who brings field experience to his engaging lectures.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 12, Title = "Modern European History", Code = "HIST 302", Description = "Europe from the French Revolution to the present day. Explores political revolutions, world wars, and modern integration.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. Catherine Blake", InstructorBio = "Dr. Blake spent a decade researching at the British National Archives before joining the faculty.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

