arguments.file_text:
@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the course catalog. Browse departments, explore courses, and submit enrollment requests.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in FeaturedCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits &middot; @course.DepartmentName</p>
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-5">Departments</h2>
<div class="row">
    @foreach (var dept in Departments)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> FeaturedCourses { get; set; } = new();
    private List<Department> Departments { get; set; } = new();

    protected override void OnInitialized()
    {
        FeaturedCourses = CatalogService.GetFeaturedCourses();
        Departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="SearchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (FilteredCourses.Any())
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in FilteredCourses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No courses match your search criteria.</p>
}

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Department> Departments { get; set; } = new();
    private List<Course> FilteredCourses => CatalogService.GetCourses(SearchTerm, SelectedDepartmentId == 0 ? null : SelectedDepartmentId);

    private string? SearchTerm { get; set; }

    private int _selectedDepartmentId;
    private int SelectedDepartmentId
    {
        get => _selectedDepartmentId;
        set => _selectedDepartmentId = value;
    }

    protected override void OnInitialized()
    {
        Departments = CatalogService.GetDepartments();
        if (DepartmentId.HasValue)
            _selectedDepartmentId = DepartmentId.Value;
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>@(Course?.Title ?? "Course Not Found")</PageTitle>

@if (Course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-secondary">Back to Courses</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@Course.Code</li>
        </ol>
    </nav>

    <h1>@Course.Code — @Course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@Course.Description</p>

            <h4 class="mt-4">Schedule</h4>
            <p>@Course.Schedule</p>

            <h4 class="mt-4">Instructor</h4>
            <p><strong>@Course.InstructorName</strong></p>
            <p>@Course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Info</h5>
                    <ul class="list-unstyled">
                        <li><strong>Credits:</strong> @Course.Credits</li>
                        <li><strong>Department:</strong> @Course.DepartmentName</li>
                        <li><strong>Code:</strong> @Course.Code</li>
                    </ul>
                    <a href="enroll?courseId=@Course.Id" class="btn btn-success w-100">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? Course { get; set; }

    protected override void OnInitialized()
    {
        Course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@Courses.FirstOrDefault(c => c.Id == Model.CourseId)?.Title</strong> has been received.</p>
        <a href="enroll" class="btn btn-outline-success">Submit Another Request</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8 col-lg-6">
            <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                    <ValidationMessage For="() => Model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
                    <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                    <div class="form-text">6–10 uppercase alphanumeric characters (e.g., STU12345)</div>
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in Courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] private EnrollmentRequest Model { get; set; } = new();

    private List<Course> Courses { get; set; } = new();
    private bool Submitted { get; set; }

    protected override void OnInitialized()
    {
        Courses = CatalogService.GetCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        Submitted = true;
    }
}

